<script>
   /*************************************************************/
   /* ModelLoader                                               */
   /* -------------------------                                 */
   /* loads preprocessing model from file                       */
   /*************************************************************/

   import { FileSelector, ButtonCancel, Container, Button } from 'svelte-controls-basic';
   import { reviver } from '../../../shared/utils';
   import { prep2str } from '../../../shared/wasm/dist/prep';
    import ModelInfo from './ModelInfo.svelte';

   let {
      model = $bindable(),
      left = $bindable(),
      right = $bindable()
   } = $props();    // object with model


   // string with model file name
   let modelFile = $state('');

   // app status for handling and showing errors
   let status = $state('neutral');
   let errMsg = $state('');

   // gets model content as one large string, parse it into matrix
   function setModel(strData) {
      try{
         const m = JSON.parse(strData, reviver);
         if (Array.isArray(m.v)) {
            m.v = Float64Array.from(m.v);
         }
         if (!Object.keys(m).includes('class') || m.class[0] !== 'prepmodel') {
            throw Error('The JSON file you selected does not contain preprocessing model.');
         }

         // validate required fields exist
         const required = ['ml', 'mpl', 'mp', 'mpl_new', 'mp_new', 'npred'];
         for (const key of required) {
            if (m[key] === undefined || m[key] === null) {
               throw Error('Preprocessing model is missing required field: ' + key + '.');
            }
         }

         // validate method count consistency
         const nm = m.ml.length;
         if (!nm || nm < 1) {
            throw Error('Preprocessing model has no methods.');
         }
         if (m.mpl.length !== nm || m.mpl_new.length !== nm) {
            throw Error('Preprocessing model has inconsistent method counts.');
         }

         // validate parameter array lengths match declared sizes
         const mpLen = m.mpl.reduce((a, v) => a + v, 0);
         const mpNewLen = m.mpl_new.reduce((a, v) => a + v, 0);
         if (m.mp.length !== mpLen) {
            throw Error('Preprocessing model has wrong parameter length (mp).');
         }
         if (m.mp_new.length !== mpNewLen) {
            throw Error('Preprocessing model has wrong parameter length (mp_new).');
         }

         // validate npred
         if (typeof m.npred !== 'number' || m.npred < 1) {
            throw Error('Preprocessing model has invalid number of predictors.');
         }

         m['fileName'] = modelFileName;
         model = m;
         status = 'success';
         errMsg = ''
      } catch (e) {
         console.log(e);
         model = null;
         status = 'error';
         errMsg = e;
      }
   }

   // promise for reading the JSON file
   function readFile (e) {
      const reader = new FileReader();
      reader.onload = () => { setModel(reader.result) };
      reader.readAsText(modelFile);
   }

   function reset() {
      modelFile = '';
      model = null;
      status = 'neutral';
      errMsg = '';
   }

   // reactive expression for tracking changes of 'modelFile'
   $effect(() => {
      if (modelFile === null) {
         // if model file is empty reset status and error messages
         model = null;
         status = 'neutral';
         errMsg = '';
      } else {
         // if not just remove error messages if any
         status = 'neutral';
         errMsg = '';
      }
   });

   $effect(() => {
      if (model === null || model === 0) modelFile = '';
   });

   // file name with model without extension
   let modelFileName =$derived(modelFile ? modelFile.name.replace(/\.[^/.]+$/, "") : '');



</script>

{#if !model }

   <!-- show if data is not loaded -->
   <!-- reset component if dataFile is changed inside -->
   {#key modelFile}
   <Container name="file-selector">
      <FileSelector id="modelFile" bind:file={modelFile} acceptType=".json" message="Select file with model"/>
   </Container>
   {/key}

   {#if modelFile}
   <Container name="load-button" label="&nbsp;">
      <Button onclick={readFile} text="Load" />
   </Container>
   {/if}

{:else}
   <!-- dataset is loaded - show info and cancel button -->
   <ModelInfo {model} {reset}/>
{/if}

<!-- error message -->
{#if status === 'error' || errMsg}
<Container name="error" status="error">
   <p>{@html errMsg}</p>
</Container>
{/if}


<style>
   :global(.prep-info) {
      position: relative;
   }

</style>